VALUES
  ('real-estate-moex-00994', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關抵押權之實行，下列敘述何者正確？', '["土地所有人於設定抵押權後，在抵押之土地上營造建築物者，抵押權人於必要時，得於強制執行程序 中聲請法院將其建築物與土地併付拍賣，對於建築物之價金，無優先受清償之權", "以建築物設定抵押權者，於法院拍賣抵押物時，其抵押物存在所必要之權利得讓與者，應併付拍賣。 但抵押權人對於該權利賣得之價金，有優先受清償之權", "設定抵押權時，土地及其土地上之建築物，同屬一人所有，而僅以土地為抵押者，於抵押物拍賣時， 得聲請併付拍賣，就土地賣得之價金，有優先受清償之權", "設定抵押權時，土地及其土地上之建築物，同屬一人所有，而以土地及建築物為抵押者，如經拍賣， 其土地與建築物之拍定人各異時，視為已有地上權之設定，其地租法院須逕以判決定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00995', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '乙將其所有汽車為甲設定動產質權，以為其對甲借款債務之擔保。該車並已交付甲之占有。下列那種情 形，甲之動產質權並不消滅？', '["丙仗義相助幫乙清償該債務", "甲將該車返還給乙", "甲喪失對該車之占有，於第3年始請求返還", "該車被盜後，隔年再讓與給善意第三人，甲對該第三人行使回復請求權時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00996', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關惡意占有人與善意占有人，在損害賠償請求方面，下列敘述何者正確？', '["善意占有人就占有物之滅失或毀損，如係不可歸責於自己之事由所致者，對於回復請求人僅以滅失或毀損 所受之利益為限，負賠償之責", "惡意占有人或無所有意思之占有人，就占有物之滅失或毀損，如係不可歸責於自己之事由所致者，對於回 復請求人，負賠償之責", "善意占有人因保存占有物所支出之必要費用，得向回復請求人請求償還。但已就占有物取得孳息者，不得 請求償還通常必要費用", "惡意占有人，因保存占有物所支出之必要費用，對於回復請求人，得依關於不當得利之規定，請求償還"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00997', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關動產善意受讓要件之說明，下列敘述何者正確？', '["讓與人與受讓人須完成讓與動產之交付行為，此之交付不包含觀念交付", "受讓人出於善意且有抽象輕過失者，不受占有之保護", "讓與人必須是無權代理", "盜贓物為金錢時，被害人不得向善意占有人請求回復"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00998', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列何者違反近親禁婚範圍之規定？', '["甲先收養丙男，再收養丁女，丙與丁之結婚", "甲有一子乙，再收養一女丙，之後乙育有一子丁，丙育有一女戊，丁與戊之結婚", "乙有一女丙，另外收養一女丁，戊有一子己，另外收養一子庚。未久，甲收養乙與戊，丙與己之結婚， 丁與庚之結婚", "甲與前妻育有一子乙，丙與前夫育有一女丁，甲與丙後來結婚，未久，乙與丁欲結婚"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00999', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列何者非屬我國現行民法中所規定之約定財產制？', '["統一財產制", "分別財產制", "一般共同財產制", "勞力所得共同財產制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01000', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關夫妻財產制的規定，下列敘述何者正確？', '["依民法規定，夫妻除可以選擇分別財產制及共同財產制外，亦得基於契約自由原則，選擇其他分配方式", "夫妻選擇分別財產制，將來離婚時仍有剩餘財產分配請求權之適用", "夫妻選擇共同財產制後，可以再變更為分別財產制，互相轉換並無次數上的限制", "夫妻因未約定夫妻財產制而採用法定財產制時，將來就不得任意再變更"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01001', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關法定夫妻財產制之敘述，下列何者錯誤？', '["夫或妻各自管理、使用、收益及處分其財產", "夫妻就其婚前財產及婚後財產，互負報告之義務", "不論夫或妻之婚前財產或婚後財產，均屬夫或妻各自所有", "夫或妻之婚前財產，於婚姻關係存續中所生之孳息，視為婚後財產"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01002', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列何者屬於剩餘財產分配請求權之標的財產？', '["婚前財產", "婚後之薪資所得", "婚後因繼承所得之財產", "婚後所取得之慰撫金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01003', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '隱瞞已婚之乙女與甲同居數年後，某日生下丙隨即離甲而去，甲獨力扶養丙，俟丙19歲生日，甲對丙告知 其生母為乙，當日丙因思母心切隨即趕赴乙家要求相認，相認時刻被乙女丈夫丁撞見，一切東窗事發，乙 丁大吵。過了2年後，上述相關人等決心為此事作一了結。試問此刻以下何人有資格提起婚生否認之訴？', '["甲", "乙", "丙", "丁"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01004', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '依我國民法之規定，當胎兒為繼承人時，他繼承人如未保留胎兒之應繼分而分割遺產者，其分割行為之 效力如何？', '["有效", "無效", "得撤銷", "效力未定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01005', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲乙為夫妻育有二女丙與丁，甲為傳香火認識已婚之戊女，同居一年後生下己男，甲把己接回家中同住 將其養育成人，但丙與己相處極為不睦，丙亦曾對己口出穢言且被判刑確定，某日丙與己再起爭執，己 一時失手將丙刺成重傷，丁見狀，起身亦把己刺成重傷，丁與己嗣後雙雙被判重刑確定，乙為此人倫悲 劇在眾人前以不堪字眼侮辱甲，甲亦默默承受，但隔日即因傷心過度辭世。試問本案中，何人對甲無繼 承權？', '["乙", "丙", "丁", "己"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01006', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關拋棄繼承之敘述，下列何者正確？', '["向戶政機關為之", "得以言詞或書面為之", "於被繼承人死亡之時起3個月內為之", "繼承之拋棄，溯及於繼承開始時發生效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01007', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列那種情形，甲所立的遺囑為有效？', '["甲6歲，經由其父母之代理而立之遺囑", "甲15歲，預立遺囑後，得其父母之追認", "甲10歲，但已得其父母之同意而立之遺囑", "甲17歲，未得其父母之允許或承認而立之遺囑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01008', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'essay', 'A建地面積130坪，乙為A地所有權人，於民國（下同）101年7月26日委由甲不
